INSERT INTO prompt_categories (slug, name_zh, description_zh, dimension, sort_order)
SELECT slug, name_zh, description_zh, dimension, sort_order
FROM seed_categories
ON CONFLICT (slug) DO UPDATE SET
    name_zh = EXCLUDED.name_zh,
    description_zh = EXCLUDED.description_zh,
    dimension = EXCLUDED.dimension,
    sort_order = EXCLUDED.sort_order,
    enabled = TRUE,
    updated_at = NOW();

WITH existing_job AS (
    SELECT id
    FROM prompt_import_jobs
    WHERE source_key = 'jisudeng-gpt-image-2-curated-seed-20260717'
    ORDER BY id
    LIMIT 1
),
created_job AS (
    INSERT INTO prompt_import_jobs (source_key, status, raw_payload)
    SELECT
        'jisudeng-gpt-image-2-curated-seed-20260717',
        'pending_review',
        jsonb_build_object(
            'brand', '极速蹬提示词库',
            'source_url', 'https://github.com/YouMind-OpenLab/awesome-gpt-image-2',
            'source_head', '51a031c7874169621688d77adb98b5efd20dd10d',
            'captured_at', '2026-07-17T04:00:00Z',
            'policy', '自动整理内容进入待审核队列，不直接发布'
        )
    WHERE NOT EXISTS (SELECT 1 FROM existing_job)
    RETURNING id
),
job AS (
    SELECT id FROM existing_job
    UNION ALL
    SELECT id FROM created_job
    LIMIT 1
),
seed_items(
    external_id, title_zh, description_zh, prompt_text, purpose, style, subject,
    model, size, reference_requirement, requires_reference, reference_instructions, media_url
) AS (
    VALUES
        ('seed-001', '白底零食主图', '适合食品零食、礼盒和商超缩略图的干净白底主图。', 'Create a clean e-commerce hero image for {{subject}} on a seamless white background, accurate edges, soft commercial lighting, subtle grounding shadow, no extra text, ready for marketplace thumbnail.', 'ecommerce-main-image', 'photography', 'food-drink', 'gpt-image-2', '1024x1024', 'optional', FALSE, '可上传商品包装参考图以保持包装细节。', '/image-studio/templates/ecom-white-bg.webp'),
        ('seed-002', '美妆瓶身套装图', '突出瓶身材质、容量层次和套装高级感。', 'Create a premium e-commerce product image for {{subject}}, arranged as a three-piece skincare set, glossy caps, translucent bottle material, bright white studio floor, elegant shadow, no text.', 'ecommerce-main-image', 'photography', 'product', 'gpt-image-2', '1024x1024', 'required', TRUE, '需要上传商品正面或包装参考图。', '/image-studio/templates/ecom-white-bg.webp'),
