inserted_items AS (
    INSERT INTO prompt_import_items (
        job_id, source_key, external_id, normalized_hash, status,
        normalized_payload, source_payload, evidence, authorization_status
    )
    SELECT
        job.id,
        'jisudeng-gpt-image-2-curated-seed-20260717',
        seed_items.external_id,
        md5('jisudeng-gpt-image-2-curated-seed-20260717:' || seed_items.external_id || ':' || seed_items.prompt_text),
        'pending_review',
        jsonb_build_object(
            'external_id', seed_items.external_id,
            'title_zh', seed_items.title_zh,
            'description_zh', seed_items.description_zh,
            'prompt_text', seed_items.prompt_text,
            'variables', jsonb_build_object(
                'subject', jsonb_build_object('label', '主体', 'description', '要生成的核心对象、人物或主题', 'required', TRUE),
                'text', jsonb_build_object('label', '中文文案', 'description', '画面中需要预留或生成的短文案', 'required', FALSE),
                'color', jsonb_build_object('label', '品牌颜色', 'description', '主色或色彩倾向，例如科技蓝、奶油白、黑金', 'required', FALSE),
                'scene', jsonb_build_object('label', '场景补充', 'description', '补充使用环境、氛围或构图要求', 'required', FALSE)
            ),
            'models', jsonb_build_array(seed_items.model),
            'sizes', jsonb_build_array(seed_items.size),
            'reference_requirement', seed_items.reference_requirement,
            'reference_instructions', seed_items.reference_instructions,
            'requires_reference', seed_items.requires_reference,
            'media', CASE
                WHEN seed_items.media_url <> '' THEN jsonb_build_array(jsonb_build_object(
                    'media_type', 'image',
                    'url', seed_items.media_url,
                    'alt_zh', seed_items.title_zh || '示例效果',
                    'sort_order', 0
                ))
                ELSE '[]'::jsonb
            END,
            'purpose', seed_items.purpose,
            'style', seed_items.style,
            'subject', seed_items.subject,
            'brand_type', 'curated',
            'authorization_status', 'curated',
            'evidence_verified', TRUE,
