UPDATE prompt_import_jobs
SET item_count = (
        SELECT COUNT(*)
        FROM prompt_import_items
        WHERE job_id = prompt_import_jobs.id
    ),
    updated_at = NOW()
WHERE id = (SELECT id FROM job);
